#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long X, Y; scanf("%d %lld %lld", &N, &X, &Y);
        long long A[1005], B[1005];
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        for(int i=0;i<N;i++) scanf("%lld", &B[i]);
        bool ok = true;
        for(int i=0;i<N;i++){
            long long d = B[i] - A[i];
            if(d != X && d != Y){ ok = false; break; }
        }
        printf("%s", ok?"yes":"no");
        if(T) printf("\n");
    }
    return 0;
}

